767	static std::string common_chat_template_direct_apply_impl(
768	    const common_chat_template & tmpl,
769	    const autoparser::generation_params & inputs,
770	    const std::optional<json> & messages_override = std::nullopt,
771	    const std::optional<json> & tools_override = std::nullopt,
772	    const std::optional<json> & additional_context = std::nullopt) {
773	    jinja::context ctx(tmpl.source());
774	
775	    nlohmann::ordered_json inp = nlohmann::ordered_json{
776	        {"messages", messages_override.has_value() ? *messages_override : inputs.messages},
777	        {"bos_token", tmpl.bos_token()},
778	        {"eos_token", tmpl.eos_token()},
779	        {"enable_thinking", inputs.enable_thinking},
780	    };
781	    if (tools_override.has_value() || !inputs.tools.empty()) {
782	        inp["tools"] = tools_override.has_value() ? *tools_override : inputs.tools;
783	    }
784	    if (inputs.extra_context.is_object()) {
785	        // TODO: do we need to merge, or replacing is fine?
786	        for (const auto & [k, v] : inputs.extra_context.items()) {
787	            inp[k] = v;
788	        }
789	    }
790	    if (additional_context.has_value()) {
791	        // TODO: merge properly instead of overwriting (matching old behavior)
792	        for (const auto & [k, v] : additional_context->items()) {
793	            inp[k] = v;
794	        }
795	    }
796	    if (inputs.add_generation_prompt) {
797	        inp["add_generation_prompt"] = true;
798	    }
799	
800	    jinja::global_from_json(ctx, inp, inputs.mark_input);
801	
802	    // render
803	    jinja::runtime runtime(ctx);
804	    const jinja::value results = runtime.execute(tmpl.prog);
805	    auto parts = jinja::runtime::gather_string_parts(results);
806	
807	    std::string result = parts->as_string().str();
808	
809	    // TODO: improve this later
810	    if (inputs.add_bos && string_starts_with(result, tmpl.bos_token())) {
811	        result = result.substr(tmpl.bos_token().size());
812	    }
813	    if (inputs.add_eos && string_ends_with(result, tmpl.eos_token())) {
814	        result = result.substr(0, result.size() - tmpl.eos_token().size());
815	    }
816	    return result;
817	}
